part of 'festival.dart';

Festival _$FestivalFromJson(Map<String, dynamic> json) => Festival(
	id: (json['id'] as num).toInt(),
	name: json['name'] as String,
	nameLocal: json['nameLocal'] as String?,
	nameEnglish: json['nameEnglish'] as String?,
	type: (json['type'] as num).toInt(),
	regionId: (json['regionId'] as num?)?.toInt(),
	ethnicityId: (json['ethnicityId'] as num?)?.toInt(),
	startDate: json['startDate'] as String?,
	endDate: json['endDate'] as String?,
	duration: (json['duration'] as num?)?.toInt() ?? 1,
	isLunar: (json['isLunar'] as num?)?.toInt() ?? 0,
	isHoliday: (json['isHoliday'] as num?)?.toInt() ?? 0,
	holidayDays: (json['holidayDays'] as num?)?.toInt(),
	description: json['description'] as String?,
	history: json['history'] as String?,
	customs: json['customs'] as String?,
	food: json['food'] as String?,
	clothing: json['clothing'] as String?,
	activities: json['activities'] as String?,
	imageUrl: json['imageUrl'] as String?,
	videoUrl: json['videoUrl'] as String?,
	status: (json['status'] as num?)?.toInt() ?? 1,
);

Map<String, dynamic> _$FestivalToJson(Festival instance) => <String, dynamic>{
	'id': instance.id,
	'name': instance.name,
	'nameLocal': instance.nameLocal,
	'nameEnglish': instance.nameEnglish,
	'type': instance.type,
	'regionId': instance.regionId,
	'ethnicityId': instance.ethnicityId,
	'startDate': instance.startDate,
	'endDate': instance.endDate,
	'duration': instance.duration,
	'isLunar': instance.isLunar,
	'isHoliday': instance.isHoliday,
	'holidayDays': instance.holidayDays,
	'description': instance.description,
	'history': instance.history,
	'customs': instance.customs,
	'food': instance.food,
	'clothing': instance.clothing,
	'activities': instance.activities,
	'imageUrl': instance.imageUrl,
	'videoUrl': instance.videoUrl,
	'status': instance.status,
};
